if (! function_exists('html_to_text')) {
    function html_to_text($html, $extract_links = null, $max_text_length = null, $remove_nav = null)
    {
        if (!is_string($html) || $html === '') {
            return ['error' => 'HTML content is required.', 'title' => '', 'text' => '', 'links' => []];
        }

        $extract_links = isset($extract_links) ? (bool)$extract_links : true;
        $max_text_length = isset($max_text_length) ? max(0, min(500000, (int)$max_text_length)) : 50000;
        $remove_nav = isset($remove_nav) ? (bool)$remove_nav : true;

        // Suppress DOM warnings for malformed HTML
        $libxml_previous = libxml_use_internal_errors(true);

        $dom = new DOMDocument();
        // Attempt to load as HTML (libxml will add doctype/html/body wrapper)
        $loaded = $dom->loadHTML('<?xml encoding="UTF-8">' . $html);

        libxml_use_internal_errors($libxml_previous);

        if (!$loaded) {
            return ['error' => 'Failed to parse HTML content.', 'title' => '', 'text' => '', 'links' => []];
        }

        $xpath = new DOMXPath($dom);

        // Extract title
        $title_node = $xpath->query('//title')->item(0);
        $title = $title_node ? trim($title_node->textContent) : '';

        // Remove unwanted elements
        if ($remove_nav) {
            // Remove script, style, noscript, iframe, nav, header, footer, aside
            foreach (['//script', '//style', '//noscript', '//iframe', '//nav', '//header', '//footer', '//aside'] as $expr) {
                $nodes = $xpath->query($expr);
                foreach ($nodes as $node) {
                    $node->parentNode->removeChild($node);
                }
            }
        } else {
            foreach (['//script', '//style', '//noscript', '//iframe'] as $expr) {
                $nodes = $xpath->query($expr);
                foreach ($nodes as $node) {
                    $node->parentNode->removeChild($node);
                }
            }
        }

        // Extract links before modifying the DOM further
        $links = [];
        if ($extract_links) {
            $anchor_nodes = $xpath->query('//a[@href]');
            foreach ($anchor_nodes as $anchor) {
                $href = $anchor->getAttribute('href');
                // Skip empty anchors, javascript:, #
                if ($href === '' || $href === '#' || str_starts_with($href, 'javascript:')) {
                    continue;
                }
                $text = trim($anchor->textContent);
                $links[] = [
                    'href' => $href,
                    'text' => mb_strlen($text) > 200 ? mb_substr($text, 0, 200) . '...' : $text,
                ];
            }
        }

        // Extract text from body. Fall back to whole document if no body.
        $body_nodes = $xpath->query('//body');
        $text = '';
        if ($body_nodes->length > 0) {
            $text = $body_nodes->item(0)->textContent;
        } else {
            $text = $dom->textContent;
        }

        // Clean up whitespace
        // Replace non-breaking spaces with regular spaces
        $text = str_replace("\xc2\xa0", ' ', $text);
        $text = str_replace("\xa0", ' ', $text);

        // Collapse whitespace: multiple spaces/newlines become single newlines between blocks
        $text = preg_replace('/[ \t]+/', ' ', $text);
        $text = preg_replace('/\n{3,}/', "\n\n", $text);
        $text = trim($text);

        // Truncate if needed
        $truncated = false;
        if ($max_text_length > 0 && mb_strlen($text) > $max_text_length) {
            $text = mb_substr($text, 0, $max_text_length) . "\n\n[... truncated ...]";
            $truncated = true;
        }

        return [
            'title' => $title,
            'text' => $text,
            'text_length' => mb_strlen($text),
            'text_truncated' => $truncated,
            'links' => $links,
            'link_count' => count($links),
            'error' => null,
        ];
    }
